#include <stdio.h>
#include <ctype.h>
#include <stdlib.h>

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        char *s = (char*)malloc(N+2);
        scanf("%s", s);
        long long *st = (long long*)malloc((N+1)*sizeof(long long));
        int top = 0;
        for (int i = 0; i < N; ++i) {
            char c = s[i];
            if (isdigit(c)) {
                st[top++] = c - '0';
            } else {
                long long b = st[--top];
                long long a = st[--top];
                long long res = 0;
                if (c == '+') res = a + b;
                else if (c == '-') res = a - b;
                else if (c == '*') res = a * b;
                st[top++] = res;
            }
        }
        printf("%lld\n", st[top-1]);
        free(s);
        free(st);
    }
    return 0;
}

