import sys

def evaluate(expr: str) -> int:
    stack = []
    for ch in expr:
        if ch.isdigit():
            stack.append(int(ch))
        else:
            b = stack.pop()
            a = stack.pop()
            if ch == '+':
                stack.append(a + b)
            elif ch == '-':
                stack.append(a - b)
            else:  # '*'
                stack.append(a * b)
    return stack[0]

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        expr = next(it)
        out_lines.append(str(evaluate(expr)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    main()

